const AdminBlog = () => {
  return (
    <section className="container mx-auto px-4 py-12">
      <h1 className="section-title">Blog Management</h1>
      <p className="section-subtitle">Create and update articles for the studio blog.</p>
      <div className="card p-8 mt-8">
        <p className="text-gray-600">Use the blog section to publish news, storytelling, and photography advice.</p>
      </div>
    </section>
  );
};

export default AdminBlog;
